  "inlineSchema": "//\n// FUSION BYTE CRM ENTERPRISE DATABASE SCHEMA (PHASE 4: AUDIT ENGINE)\n//\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ==========================================\n// ENUMS (Strict State Machines)\n// ==========================================\n\nenum Role {\n  OWNER\n  ADMIN\n  MEMBER\n}\n\nenum LeadStatus {\n  NEW\n  CONTACTED\n  QUALIFIED\n  PROPOSAL\n  WON\n  LOST\n}\n\nenum DealStage {\n  DISCOVERY\n  PROPOSAL\n  NEGOTIATION\n  CLOSED_WON\n  CLOSED_LOST\n}\n\nenum TaskStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETED\n}\n\nenum TaskPriority {\n  LOW\n  MEDIUM\n  HIGH\n}\n\n// ==========================================\n// CORE TENANT ARCHITECTURE\n// ==========================================\n\nmodel Workspace {\n  id        String   @id @default(uuid())\n  tenantUid String   @unique\n  name      String\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relational Web\n  users     User[]\n  leads     Lead[]\n  companies Company[]\n  contacts  Contact[]\n  deals     Deal[]\n  tasks     Task[]\n  notes     Note[]\n\n  @@index([tenantUid])\n}\n\nmodel User {\n  id          String   @id @default(uuid())\n  workspaceId String\n  firebaseUid String   @unique\n  email       String   @unique\n  fullName    String\n  role        Role     @default(MEMBER)\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace     Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  createdLeads  Lead[]    @relation(\"UserToLead\")\n  ownedDeals    Deal[]    @relation(\"UserToDeal\")\n  assignedTasks Task[]    @relation(\"UserToTask\")\n  createdNotes  Note[]    @relation(\"UserToNote\")\n\n  @@index([workspaceId])\n  @@index([firebaseUid])\n}\n\n// ==========================================\n// PHASE 1: PIPELINE ENGINE\n// ==========================================\n\nmodel Lead {\n  id              String     @id @default(uuid())\n  workspaceId     String\n  createdByUserId String\n  firstName       String\n  lastName        String?\n  email           String?\n  phone           String?\n  status          LeadStatus @default(NEW)\n  order           Int        @default(0)\n  source          String     @default(\"MANUAL\")\n\n  isDeleted Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  createdBy User      @relation(\"UserToLead\", fields: [createdByUserId], references: [id])\n  notes     Note[]\n\n  @@index([workspaceId])\n  @@index([status])\n}\n\n// ==========================================\n// PHASE 2: THE RELATIONAL WEB\n// ==========================================\n\nmodel Company {\n  id          String  @id @default(uuid())\n  workspaceId String\n  name        String\n  industry    String?\n  website     String?\n  address     String?\n\n  isDeleted Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  contacts  Contact[]\n  deals     Deal[]\n  notes     Note[]\n\n  @@index([workspaceId])\n}\n\nmodel Contact {\n  id          String  @id @default(uuid())\n  workspaceId String\n  companyId   String?\n  firstName   String\n  lastName    String?\n  email       String?\n  phone       String?\n  title       String?\n\n  isDeleted Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  company   Company?  @relation(fields: [companyId], references: [id], onDelete: SetNull)\n  deals     Deal[]\n  notes     Note[]\n\n  @@index([workspaceId])\n  @@index([companyId])\n}\n\nmodel Deal {\n  id                String    @id @default(uuid())\n  workspaceId       String\n  companyId         String?\n  contactId         String?\n  ownerId           String\n  title             String\n  value             Float     @default(0.0)\n  stage             DealStage @default(DISCOVERY)\n  expectedCloseDate DateTime?\n\n  isDeleted Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  company   Company?  @relation(fields: [companyId], references: [id], onDelete: SetNull)\n  contact   Contact?  @relation(fields: [contactId], references: [id], onDelete: SetNull)\n  owner     User      @relation(\"UserToDeal\", fields: [ownerId], references: [id])\n  tasks     Task[]\n  notes     Note[]\n\n  @@index([workspaceId])\n  @@index([ownerId])\n  @@index([stage])\n}\n\n// ==========================================\n// PHASE 3: THE ACTION ENGINE (TASKS)\n// ==========================================\n\nmodel Task {\n  id          String       @id @default(uuid())\n  workspaceId String\n  assigneeId  String\n  dealId      String?\n  title       String\n  description String?      @db.Text\n  status      TaskStatus   @default(PENDING)\n  priority    TaskPriority @default(MEDIUM)\n  dueDate     DateTime?\n\n  isDeleted Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  assignee  User      @relation(\"UserToTask\", fields: [assigneeId], references: [id])\n  deal      Deal?     @relation(fields: [dealId], references: [id], onDelete: SetNull)\n\n  @@index([workspaceId])\n  @@index([assigneeId])\n  @@index([dealId])\n}\n\n// ==========================================\n// PHASE 4: THE AUDIT & NOTES ENGINE (NEW)\n// ==========================================\n\nmodel Note {\n  id              String  @id @default(uuid())\n  workspaceId     String\n  createdByUserId String\n  content         String  @db.Text\n  isSystem        Boolean @default(false) // If true, it's an auto-generated audit log\n\n  // Polymorphic Links (Can belong to any ONE of these)\n  leadId    String?\n  companyId String?\n  contactId String?\n  dealId    String?\n\n  isDeleted Boolean  @default(false)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @default(now()) @updatedAt\n\n  // Relationships\n  workspace Workspace @relation(fields: [workspaceId], references: [id], onDelete: Cascade)\n  createdBy User      @relation(\"UserToNote\", fields: [createdByUserId], references: [id])\n\n  lead    Lead?    @relation(fields: [leadId], references: [id], onDelete: Cascade)\n  company Company? @relation(fields: [companyId], references: [id], onDelete: Cascade)\n  contact Contact? @relation(fields: [contactId], references: [id], onDelete: Cascade)\n  deal    Deal?    @relation(fields: [dealId], references: [id], onDelete: Cascade)\n\n  @@index([workspaceId])\n  @@index([leadId])\n  @@index([companyId])\n  @@index([contactId])\n  @@index([dealId])\n}\n",
